;(function(){System.register([],function(exports,module){'use strict';return{execute:function(){(Drupal2=>{const odsOlu={elements:{links:document.querySelectorAll("[data-olu]")},methods:{initialize:()=>{const{handleRedirect}=odsOlu.events;[...odsOlu.elements.links].forEach(link=>{const hash=link.getAttribute("data-olu");if(!hash||!hash.length){return;}link.addEventListener("click",()=>handleRedirect(link,hash));odsOlu.events.handleKeyBoardNavigation(link);});odsOlu.events.handleCustomEvent();}},events:{handleRedirect:(link,hash)=>{const hashReversed=hash.split("").reverse().join("");const url=atob(hashReversed);const target=link.getAttribute("data-olu-target")||"_self";window.open(url,target);},handleKeyBoardNavigation:link=>{link.addEventListener("keydown",event=>{if(["Enter","Space"].includes(event.code)){link.click();}});},handleCustomEvent:()=>{document.addEventListener("dataOluLoad",()=>{odsOlu.elements.links=document.querySelectorAll("[data-olu]");odsOlu.methods.initialize();},{once:true});}},attach:()=>{odsOlu.methods.initialize();}};Drupal2.behaviors.odsOlu=odsOlu;})(Drupal);}};});})();
